import os
import subprocess
from google.cloud import storage

def secure_image_conversion(data, context):
    bucket_name = data['bucket']
    file_name = data['name']
    metadata = data.get('metadata', {})
    conversion_options = metadata.get('conversion_options', '')

    # Validate and sanitize conversion options
    allowed_options = ['-resize', '-rotate', '-quality']
    sanitized_options = []
    for option in conversion_options.split():
        if any(option.startswith(allowed) for allowed in allowed_options):
            sanitized_options.append(option)

    # Construct the secure command
    source_path = f"/tmp/{file_name}"
    destination_path = f"/tmp/converted-{file_name}"
    command = ['convert', source_path] + sanitized_options + [destination_path]

    # Download the file from Cloud Storage
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    blob.download_to_filename(source_path)

    # Execute the ImageMagick command
    subprocess.call(command)

    # Upload the converted image back to Cloud Storage
    converted_blob = bucket.blob(f"converted/{file_name}")
    converted_blob.upload_from_filename(destination_path)

    # Clean up temporary files
    os.remove(source_path)
    os.remove(destination_path)